-- STEP 2: query [kvikkleire]
SELECT omrade FROM kvikkleire_175185730654415d8841436d0d6999f2.kartleggingsomrade WHERE ST_Intersects(omrade, (SELECT omrade FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenummer = '5001' AND gyldigtil IS NULL)) ;

